import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { getArtistes, deleteArtiste } from '../api/artisteService';

export default function ArtistesList(){
  const [artistes, setArtistes] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetch = () => {
    setLoading(true);
    getArtistes().then(r=>{ setArtistes(r.data || []); }).catch(()=>{}).finally(()=>setLoading(false));
  };

  useEffect(()=>{ fetch(); }, []);

  const handleDelete = (id) => {
    if(!window.confirm('Supprimer cet artiste ?')) return;
    deleteArtiste(id).then(()=>fetch());
  };

  return (
    <div>
      <h1>Artistes</h1>
      <p><Link to="/artistes/create">Créer un artiste</Link></p>
      {loading ? <div>Chargement...</div> : (
        <ul>
          {artistes.map(a => (
            <li key={a.id} style={{marginBottom:8}}>
              <Link to={`/artistes/${a.id}`}>{a.nom || a.name || `Artiste ${a.id}`}</Link>
              {' '}
              <Link to={`/artistes/${a.id}/edit`} style={{marginLeft:8}}>Modifier</Link>
              <button onClick={()=>handleDelete(a.id)} style={{marginLeft:8}}>Supprimer</button>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}
